import { useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import { Button } from "../components/ui/simplebutton";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "../components/ui/card";
import { Badge } from "../components/ui/badge";
import { Progress } from "../components/ui/progress";
import { Avatar, AvatarFallback, AvatarImage } from "../components/ui/avatar";
import { SidebarProvider, SidebarInset, SidebarTrigger } from "../components/ui/sidebar";
import StudentSidebar from "../components/StudentSidebar";
import ApiService from "../api";

const StudentDashboard = () => {
  const navigate = useNavigate();
  const userName = localStorage.getItem("userName") || "Student";
  const userEmail = localStorage.getItem("userEmail") || "";
  const studentClass = localStorage.getItem("studentClass") || "6";
  
  const [dashboardData, setDashboardData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const handleLogout = () => {
    localStorage.removeItem("userType");
    localStorage.removeItem("userName");
    localStorage.removeItem("studentClass");
    localStorage.removeItem("userEmail");
    navigate("/");
  };

  useEffect(() => {
    const fetchDashboardData = async () => {
      try {
        setLoading(true);
        const data = await ApiService.getStudentDashboard(userEmail);
        setDashboardData(data);
        setError(null);
      } catch (err) {
        console.error('Failed to fetch dashboard data:', err);
        setError('Failed to load dashboard data');
      } finally {
        setLoading(false);
      }
    };

    if (userEmail) {
      fetchDashboardData();
    } else {
      setLoading(false);
      setError('No user email found');
    }
  }, [userEmail]);

  if (loading) {
    return (
      <SidebarProvider>
        <StudentSidebar />
        <SidebarInset>
          <div className="min-h-screen bg-gradient-to-br from-background via-background to-primary/5 flex items-center justify-center">
            <div className="text-center">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto mb-4"></div>
              <p className="text-muted-foreground">Loading dashboard...</p>
            </div>
          </div>
        </SidebarInset>
      </SidebarProvider>
    );
  }

  if (error) {
    return (
      <SidebarProvider>
        <StudentSidebar />
        <SidebarInset>
          <div className="min-h-screen bg-gradient-to-br from-background via-background to-primary/5 flex items-center justify-center">
            <div className="text-center">
              <p className="text-red-500 mb-4">{error}</p>
              <Button onClick={() => window.location.reload()}>Try Again</Button>
            </div>
          </div>
        </SidebarInset>
      </SidebarProvider>
    );
  }

  const stats = dashboardData?.overall_stats || {};
  const studentInfo = dashboardData?.student || {};
  const subjectProgress = dashboardData?.subject_progress || [];
  const recentActivity = dashboardData?.recent_activity || [];

  return (
    <SidebarProvider>
      <StudentSidebar />
      <SidebarInset>
        <div className="min-h-screen bg-gradient-to-br from-background via-background to-primary/5">
          {/* Header */}
          <header className="border-b bg-background/80 backdrop-blur-sm sticky top-0 z-50">
            <div className="container mx-auto px-4 py-4 flex items-center justify-between">
              <div className="flex items-center gap-4">
                <SidebarTrigger className="md:hidden" />
                <div className="w-8 h-8 rounded-full bg-gradient-primary flex items-center justify-center">
                  <span className="text-lg">🎓</span>
                </div>
                <h1 className="text-xl font-bold bg-gradient-primary bg-clip-text text-white">
                  EdUmbrella
                </h1>
              </div>
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <Avatar className="w-8 h-8">
                    <AvatarImage src="/placeholder.svg" />
                    <AvatarFallback>{(studentInfo.name || userName).charAt(0).toUpperCase()}</AvatarFallback>
                  </Avatar>
                  <span className="text-sm font-medium">{studentInfo.name || userName}</span>
                </div>
                <Button variant="outline" onClick={handleLogout}>
                  Logout
                </Button>
              </div>
            </div>
          </header>

          <div className="container mx-auto px-4 py-8">
            <div className="mb-8">
              <h2 className="text-3xl font-bold mb-2">Welcome back, {studentInfo.name || userName}! 🌟</h2>
              <p className="text-muted-foreground">Class {studentInfo.class || studentClass} • Continue your learning journey and level up your skills</p>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {/* Progress Overview */}
          <Card className="col-span-full lg:col-span-2">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                📊 Learning Progress
                <Badge variant="secondary">
                  {stats.completed_quizzes >= 20 ? 'Expert' : 
                   stats.completed_quizzes >= 10 ? 'Advanced' : 
                   stats.completed_quizzes >= 5 ? 'Intermediate' : 'Beginner'}
                </Badge>
              </CardTitle>
              <CardDescription>Your overall learning statistics</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div className="space-y-2">
                  <div className="flex justify-between text-sm">
                    <span>Average Score</span>
                    <span className="font-bold text-primary">{Math.round(stats.average_score || 0)}%</span>
                  </div>
                  <Progress value={stats.average_score || 0} className="h-2" />
                </div>
                <div className="space-y-2">
                  <div className="flex justify-between text-sm">
                    <span>Quizzes Completed</span>
                    <span className="font-bold text-primary">{stats.completed_quizzes || 0}</span>
                  </div>
                  <Progress value={Math.min((stats.completed_quizzes || 0) * 5, 100)} className="h-2" />
                </div>
                <div className="space-y-2">
                  <div className="flex justify-between text-sm">
                    <span>Time Spent</span>
                    <span className="font-bold text-primary">{Math.round(stats.total_time_spent || 0)}min</span>
                  </div>
                  <Progress value={Math.min((stats.total_time_spent || 0) / 10, 100)} className="h-2" />
                </div>
              </div>
            </CardContent>
          </Card>

          {/* Achievements */}
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                🏆 Achievements
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              {stats.completed_quizzes >= 10 && (
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-gradient-to-r from-yellow-400 to-orange-500 flex items-center justify-center">
                    ⭐
                  </div>
                  <div>
                    <div className="font-medium">Quiz Master</div>
                    <div className="text-sm text-muted-foreground">Completed {stats.completed_quizzes} quizzes</div>
                  </div>
                </div>
              )}
              {stats.average_score >= 80 && (
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-gradient-to-r from-green-400 to-blue-500 flex items-center justify-center">
                    🎯
                  </div>
                  <div>
                    <div className="font-medium">High Scorer</div>
                    <div className="text-sm text-muted-foreground">{Math.round(stats.average_score)}% average score</div>
                  </div>
                </div>
              )}
              {stats.completed_quizzes >= 5 && (
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-full bg-gradient-to-r from-purple-400 to-pink-500 flex items-center justify-center">
                    📚
                  </div>
                  <div>
                    <div className="font-medium">Learner</div>
                    <div className="text-sm text-muted-foreground">Started your learning journey</div>
                  </div>
                </div>
              )}
              {stats.completed_quizzes === 0 && (
                <div className="text-center text-muted-foreground py-4">
                  <p>Complete your first quiz to earn badges!</p>
                </div>
              )}
            </CardContent>
          </Card>

          {/* Subjects */}
          <Card>
            <CardHeader>
              <CardTitle>📚 My Subjects</CardTitle>
              <CardDescription>Class {studentInfo.class || studentClass} subjects with your progress</CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              {subjectProgress.length > 0 ? (
                subjectProgress.map((subject, index) => (
                  <div key={index} className="flex items-center justify-between p-3 border rounded">
                    <div className="flex items-center gap-3">
                      <span className="text-lg">{subject.icon || '📚'}</span>
                      <div>
                        <div className="font-medium">{subject.name}</div>
                        <div className="text-sm text-muted-foreground">
                          {subject.completed_content || 0} / {subject.total_content || 0} completed
                        </div>
                      </div>
                    </div>
                    <div className="text-right">
                      <div className="text-sm font-medium text-primary">
                        {Math.round(subject.average_score || 0)}%
                      </div>
                      <Progress 
                        value={subject.total_content ? (subject.completed_content / subject.total_content) * 100 : 0} 
                        className="w-16 h-2 mt-1" 
                      />
                    </div>
                  </div>
                ))
              ) : (
                <div className="text-center text-muted-foreground py-4">
                  <p>No subjects available for your class level.</p>
                </div>
              )}
            </CardContent>
          </Card>

          {/* Quick Actions */}
          <Card>
            <CardHeader>
              <CardTitle>⚡ Quick Actions</CardTitle>
            </CardHeader>
            <CardContent className="space-y-3">
              <Button className="w-full">
                 Take a Quiz
              </Button>
              <Button variant="outline" className="w-full">
                 Practice Problems
              </Button>
              <Button variant="outline" className="w-full">
                 View Analytics
              </Button>
              <Button variant="outline" className="w-full">
               View Lectures
              </Button>

            </CardContent>
          </Card>

          {/* Recent Activity */}
          <Card>
            <CardHeader>
              <CardTitle>📈 Recent Activity</CardTitle>
              <CardDescription>Your latest quiz attempts and games</CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              {recentActivity.length > 0 ? (
                recentActivity.slice(0, 5).map((activity, index) => (
                  <div key={index} className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <span className="text-lg">{activity.subject_icon === 'game' ? '🎮' : (activity.subject_icon || '📚')}</span>
                      <div>
                        <span className="font-medium text-sm">{activity.activity_name}</span>
                        <div className="text-xs text-muted-foreground">
                          {activity.subject_name} • Class {activity.class_level}
                        </div>
                      </div>
                    </div>
                    <div className="text-right">
                      <span className="text-sm font-bold text-primary">{Math.round(activity.score || 0)}%</span>
                      <div className="text-xs text-muted-foreground">
                        {new Date(activity.activity_date).toLocaleDateString()}
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="text-center text-muted-foreground py-4">
                  <p>No recent activity. Start taking quizzes to see your progress here!</p>
                </div>
              )}
            </CardContent>
          </Card>
            </div>
          </div>
        </div>
      </SidebarInset>
    </SidebarProvider>
  );
};

export default StudentDashboard;