import { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import {
  Home,
  Users,
  BookOpen,
  FileText,
  Upload,
  BarChart3,
  Settings,
  Calendar
} from "lucide-react";

import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarGroup,
  SidebarGroupContent,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarSeparator,
} from "./ui/sidebar";
import { Avatar, AvatarFallback, AvatarImage } from "./ui/avatar";
import { Badge } from "./ui/badge";

const TeacherSidebar = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const userName = localStorage.getItem("userName") || "Teacher";
  const [activeItem, setActiveItem] = useState("");

  const navigationItems = [
    {
      id: "dashboard",
      label: "Dashboard",
      icon: Home,
      path: "/teacher-dashboard",
    },
    {
      id: "classes",
      label: "Classes",
      icon: BookOpen,
      path: "/teacher/classes",
    },
    {
      id: "quizzes",
      label: "Quizzes",
      icon: FileText,
      path: "/teacher/quizzes",
      badge: "3"
    },
    {
      id: "content",
      label: "Content",
      icon: Upload,
      path: "/teacher/content",
    },
    {
      id: "schedule",
      label: "Schedule",
      icon: Calendar,
      path: "/teacher/schedule",
    },
    {
      id: "settings",
      label: "Settings",
      icon: Settings,
      path: "/teacher/settings",
    },
  ];

  // Set active item based on current route
  useEffect(() => {
    const currentPath = location.pathname;
    if (currentPath === "/teacher-dashboard") {
      setActiveItem("dashboard");
    } else if (currentPath.startsWith("/teacher/classes")) {
      setActiveItem("classes");
    } else if (currentPath.startsWith("/teacher/quizzes")) {
      setActiveItem("quizzes");
    } else if (currentPath.startsWith("/teacher/content")) {
      setActiveItem("content");
    } else if (currentPath.startsWith("/teacher/schedule")) {
      setActiveItem("schedule");
    } else if (currentPath.startsWith("/teacher/settings")) {
      setActiveItem("settings");
    } else {
      setActiveItem(""); // No active item for unknown routes
    }
  }, [location.pathname]);

  const handleNavigation = (item: typeof navigationItems[0]) => {
    setActiveItem(item.id);
    navigate(item.path);
  };

  return (
    <Sidebar className="bg-black border-r border-gray-800">
      <SidebarHeader className="p-4 bg-black">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-full bg-gradient-to-r from-green-500 to-blue-600 flex items-center justify-center">
            <img src="/favicon.ico" alt="EdUmbrella Logo" className="w-6 h-6" />
          </div>
          <div className="flex flex-col">
            <h2 className="text-lg font-bold text-white">EdUmbrella</h2>
            <p className="text-xs text-gray-300">Teacher Portal</p>
          </div>
        </div>
      </SidebarHeader>

      <SidebarSeparator className="bg-gray-800" />

      <SidebarContent className="bg-black">
        <SidebarGroup className="bg-black">
          <SidebarGroupContent>
            <SidebarMenu>
              {navigationItems.map((item) => (
                <SidebarMenuItem key={item.id}>
                  <SidebarMenuButton
                    isActive={activeItem === item.id}
                    onClick={() => handleNavigation(item)}
                    className="w-full text-white hover:bg-gray-800 hover:text-white data-[active=true]:bg-gray-900 data-[active=true]:text-white data-[active=true]:border-l-2 data-[active=true]:border-green-500"
                  >
                    <item.icon className="w-4 h-4 text-white" />
                    <span className="text-white">{item.label}</span>
                    {item.badge && (
                      <Badge variant="secondary" className="ml-auto bg-gray-700 text-white hover:bg-gray-600">
                        {item.badge}
                      </Badge>
                    )}
                  </SidebarMenuButton>
                </SidebarMenuItem>
              ))}
            </SidebarMenu>
          </SidebarGroupContent>
        </SidebarGroup>
      </SidebarContent>

      <SidebarSeparator className="bg-gray-800" />

      <SidebarFooter className="p-4 bg-black">
        <div className="flex items-center gap-3">
          <Avatar className="w-8 h-8">
            <AvatarImage src="/placeholder.svg" />
            <AvatarFallback className="bg-gradient-to-r from-green-500 to-blue-600 text-white">
              {userName.charAt(0).toUpperCase()}
            </AvatarFallback>
          </Avatar>
          <div className="flex flex-col min-w-0">
            <span className="text-sm font-medium text-white truncate">
              {userName}
            </span>
            <span className="text-xs text-gray-300">Teacher</span>
          </div>
        </div>
      </SidebarFooter>
    </Sidebar>
  );
};

export default TeacherSidebar;