import { useState, useEffect } from "react";
import { useNavigate, useLocation } from "react-router-dom";
import {
  BookOpen,
  FileText,
  Trophy,
  Calendar,
  User,
  Gamepad2,
  Home
} from "lucide-react";

import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarGroup,
  SidebarGroupContent,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarSeparator,
} from "./ui/sidebar";
import { Avatar, AvatarFallback, AvatarImage } from "./ui/avatar";
import { Badge } from "./ui/badge";

const StudentSidebar = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const userName = localStorage.getItem("userName") || "Student";
  const [activeItem, setActiveItem] = useState("");

  const navigationItems = [
    {
      id: "dashboard",
      label: "Dashboard",
      icon: Home,
      path: "/student-dashboard",
    },
    {
      id: "lectures",
      label: "Lectures",
      icon: BookOpen,
      path: "/lectures",
    },
    {
      id: "quizzes",
      label: "Quizzes",
      icon: FileText,
      path: "/quizzes",
      badge: "5"
    },
    {
      id: "games",
      label: "Games",
      icon: Gamepad2,
      path: "/games",
      badge: "3"
    },
    {
      id: "leaderboard",
      label: "Leaderboard",
      icon: Trophy,
      path: "/leaderboard",
    },
    {
      id: "calendar",
      label: "Calendar",
      icon: Calendar,
      path: "/calendar",
    },
    {
      id: "profile",
      label: "Profile",
      icon: User,
      path: "/profile",
    },
  ];

  // Set active item based on current route
  useEffect(() => {
    const currentPath = location.pathname;
    if (currentPath === "/student-dashboard") {
      setActiveItem("dashboard");
    } else if (currentPath.startsWith("/lectures")) {
      setActiveItem("lectures");
    } else if (currentPath.startsWith("/quizzes")) {
      setActiveItem("quizzes");
    } else if (currentPath.startsWith("/games")) {
      setActiveItem("games");
    } else if (currentPath.startsWith("/leaderboard")) {
      setActiveItem("leaderboard");
    } else if (currentPath.startsWith("/calendar")) {
      setActiveItem("calendar");
    } else if (currentPath.startsWith("/profile")) {
      setActiveItem("profile");
    } else {
      setActiveItem(""); // No active item for unknown routes
    }
  }, [location.pathname]);

  const handleNavigation = (item: typeof navigationItems[0]) => {
    setActiveItem(item.id);
    navigate(item.path);
  };

  return (
    <Sidebar className="bg-black border-r border-gray-800">
      <SidebarHeader className="p-4 bg-black">
        <div className="flex items-center gap-3">
          <div className="w-8 h-8 rounded-full bg-gradient-to-r from-blue-500 to-purple-600 flex items-center justify-center">
            <img src="/favicon.ico" alt="EdUmbrella Logo" className="w-6 h-6" />
          </div>
          <div className="flex flex-col">
            <h2 className="text-lg font-bold text-white">EdUmbrella</h2>
            <p className="text-xs text-gray-300">Learning Platform</p>
          </div>
        </div>
      </SidebarHeader>

      <SidebarSeparator className="bg-gray-800" />

      <SidebarContent className="bg-black">
        <SidebarGroup className="bg-black">
          <SidebarGroupContent>
            <SidebarMenu>
              {navigationItems.map((item) => (
                <SidebarMenuItem key={item.id}>
                  <SidebarMenuButton
                    isActive={activeItem === item.id}
                    onClick={() => handleNavigation(item)}
                    className="w-full text-white hover:bg-gray-800 hover:text-white data-[active=true]:bg-gray-900 data-[active=true]:text-white data-[active=true]:border-l-2 data-[active=true]:border-blue-500"
                  >
                    <item.icon className="w-4 h-4 text-white" />
                    <span className="text-white">{item.label}</span>
                    {item.badge && (
                      <Badge variant="secondary" className="ml-auto bg-gray-700 text-white hover:bg-gray-600">
                        {item.badge}
                      </Badge>
                    )}
                  </SidebarMenuButton>
                </SidebarMenuItem>
              ))}
            </SidebarMenu>
          </SidebarGroupContent>
        </SidebarGroup>
      </SidebarContent>

      <SidebarSeparator className="bg-gray-800" />

      <SidebarFooter className="p-4 bg-black">
        <div className="flex items-center gap-3">
          <Avatar className="w-8 h-8">
            <AvatarImage src="/placeholder.svg" />
            <AvatarFallback className="bg-gradient-to-r from-blue-500 to-purple-600 text-white">
              {userName.charAt(0).toUpperCase()}
            </AvatarFallback>
          </Avatar>
          <div className="flex flex-col min-w-0">
            <span className="text-sm font-medium text-white truncate">
              {userName}
            </span>
            <span className="text-xs text-gray-300">Student</span>
          </div>
        </div>
      </SidebarFooter>
    </Sidebar>
  );
};

export default StudentSidebar;