import { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "../components/ui/card";
import { Badge } from "../components/ui/badge";
import { Button } from "../components/ui/simplebutton";
import { Avatar, AvatarFallback, AvatarImage } from "../components/ui/avatar";
import { SidebarProvider, SidebarInset, SidebarTrigger } from "../components/ui/sidebar";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "../components/ui/tabs";
import {
  FileText,
  Clock,
  Trophy,
  Play,
  CheckCircle2,
  AlertCircle,
  Star,
  Target,
  Gamepad2,
  Zap,
  Loader2
} from "lucide-react";
import StudentSidebar from "../components/StudentSidebar";
import ApiService from "../api";
import { mockGameQuizzes, mockTraditionalQuizzes, mockStudentProgress, filterByClass, getSubjectProgressByClass } from "../data/mockData";

const Quizzes = () => {
  const navigate = useNavigate();
  const userName = localStorage.getItem("userName") || "Student";
  const userEmail = localStorage.getItem("userEmail") || "";
  const studentClass = localStorage.getItem("studentClass") || "6"; // Default to class 6
  const [loading, setLoading] = useState(true);
  const [quizzes, setQuizzes] = useState([]);
  const [gameQuizzes, setGameQuizzes] = useState([]);
  const [studentProgress, setStudentProgress] = useState(null);
  const [error, setError] = useState(null);

  const handleLogout = () => {
    localStorage.removeItem("userType");
    localStorage.removeItem("userName");
    localStorage.removeItem("userEmail");
    localStorage.removeItem("studentClass");
    navigate("/");
  };

  // Load data from API
  useEffect(() => {
    const loadData = async () => {
      try {
        setLoading(true);
        setError(null);

        // Try to load data from API, fallback to mock data if failed
        try {
          const [quizzesResponse, gameQuizzesResponse, progressResponse] = await Promise.all([
            ApiService.getQuizzes({ type: 'traditional' }),
            ApiService.getQuizzes({ type: 'game' }),
            userEmail ? ApiService.getStudentProgress(userEmail) : Promise.resolve(null)
          ]);

          // Filter API responses based on student class
          const apiQuizzes = (quizzesResponse.quizzes || []).filter(quiz =>
            !quiz.classes || quiz.classes.includes(studentClass)
          );
          const apiGameQuizzes = (gameQuizzesResponse.quizzes || []).filter(game =>
            !game.classes || game.classes.includes(studentClass)
          );

          setQuizzes(apiQuizzes);
          setGameQuizzes(apiGameQuizzes);
          setStudentProgress(progressResponse);
        } catch (apiError) {
          console.warn('API not available, using mock data:', apiError);
          // Use shared mock data
          setQuizzes(filterByClass(mockTraditionalQuizzes, studentClass));
          setGameQuizzes(filterByClass(mockGameQuizzes, studentClass));
          setStudentProgress({
            ...mockStudentProgress,
            subject_progress: getSubjectProgressByClass(studentClass)
          });
        }

      } catch (error) {
        console.error('Failed to load quiz data:', error);
        // Don't show error, fallback handled above
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, [userEmail, studentClass]);

  const handleQuizStart = async (quiz) => {
    try {
      if (quiz.quiz_type === 'game' || quiz.game_component) {
        // Navigate to game pages
        if (quiz.game_component === 'circuit') {
          navigate('/games/circuit');
        } else if (quiz.game_component === 'nutrition') {
          navigate('/games/nutrition');
        } else if (quiz.game_component === 'pizza') {
          navigate('/games/pizza');
        } else if (quiz.game_component === 'photosynthesis') {
          navigate('/games/photosynthesis');
        } else if (quiz.game_component === 'equation') {
          navigate('/games/equation-unlock');
        } else {
          // Handle other games
          navigate(`/games/${quiz.game_component}`);
        }
      } else {
        // Start traditional quiz
        try {
          const response = await ApiService.startQuiz(quiz.id, userEmail);
          navigate(`/quiz/${quiz.id}/attempt/${response.attempt_id}`);
        } catch (apiError) {
          // If API is not available, show demo message
          alert(`Starting quiz: ${quiz.title}\n\nThis would normally start the quiz interface with questions.`);
        }
      }
    } catch (error) {
      console.error('Failed to start quiz:', error);
      alert('Unable to start quiz. Please try again.');
    }
  };

  const getDifficultyColor = (difficulty) => {
    switch (difficulty.toLowerCase()) {
      case 'easy': return 'text-green-600 bg-green-100';
      case 'medium': return 'text-yellow-600 bg-yellow-100';
      case 'hard': return 'text-red-600 bg-red-100';
      default: return 'text-gray-600 bg-gray-100';
    }
  };

  const getScoreColor = (score) => {
    if (score >= 90) return 'text-green-600';
    if (score >= 75) return 'text-blue-600';
    if (score >= 60) return 'text-yellow-600';
    return 'text-red-600';
  };

  if (loading) {
    return (
      <SidebarProvider>
        <StudentSidebar />
        <SidebarInset>
          <div className="min-h-screen bg-gradient-to-br from-background via-background to-primary/5 flex items-center justify-center">
            <div className="text-center">
              <Loader2 className="h-8 w-8 animate-spin mx-auto mb-4" />
              <p>Loading quiz data...</p>
            </div>
          </div>
        </SidebarInset>
      </SidebarProvider>
    );
  }

  if (error) {
    return (
      <SidebarProvider>
        <StudentSidebar />
        <SidebarInset>
          <div className="min-h-screen bg-gradient-to-br from-background via-background to-primary/5 flex items-center justify-center">
            <div className="text-center">
              <AlertCircle className="h-8 w-8 text-red-500 mx-auto mb-4" />
              <p className="text-red-600">{error}</p>
              <Button onClick={() => window.location.reload()} className="mt-4">
                Retry
              </Button>
            </div>
          </div>
        </SidebarInset>
      </SidebarProvider>
    );
  }

  return (
    <SidebarProvider>
      <StudentSidebar />
      <SidebarInset>
        <div className="min-h-screen bg-gradient-to-br from-background via-background to-primary/5">
          {/* Header */}
          <header className="border-b bg-background/80 backdrop-blur-sm sticky top-0 z-50">
            <div className="container mx-auto px-4 py-4 flex items-center justify-between">
              <div className="flex items-center gap-4">
                <SidebarTrigger className="md:hidden" />
                <div className="w-8 h-8 rounded-full bg-gradient-primary flex items-center justify-center">
                  <span className="text-lg">📝</span>
                </div>
                <h1 className="text-xl font-bold bg-gradient-primary bg-clip-text text-white">
                  EdUmbrella - Quizzes
                </h1>
              </div>
              <div className="flex items-center gap-4">
                <div className="flex items-center gap-2">
                  <Avatar className="w-8 h-8">
                    <AvatarImage src="/placeholder.svg" />
                    <AvatarFallback>{userName.charAt(0).toUpperCase()}</AvatarFallback>
                  </Avatar>
                  <span className="text-sm font-medium">{userName}</span>
                </div>
                <Button variant="outline" onClick={handleLogout}>
                  Logout
                </Button>
              </div>
            </div>
          </header>

          <div className="container mx-auto px-4 py-8">
            <div className="mb-8">
              <h2 className="text-3xl font-bold mb-2">📝 Quiz Center - Class {studentClass}</h2>
              <p className="text-muted-foreground">
                Test your knowledge and track your progress with content designed for your class level
              </p>
            </div>

            {/* Stats Overview */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
              <Card>
                <CardContent className="p-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center">
                      <FileText className="w-5 h-5 text-blue-600" />
                    </div>
                    <div>
                      <p className="text-sm text-muted-foreground">Total Quizzes</p>
                      <p className="text-2xl font-bold">{quizzes.length + gameQuizzes.length}</p>
                    </div>
                  </div>
                </CardContent>
              </Card>
              <Card>
                <CardContent className="p-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-green-100 flex items-center justify-center">
                      <CheckCircle2 className="w-5 h-5 text-green-600" />
                    </div>
                    <div>
                      <p className="text-sm text-muted-foreground">Completed</p>
                      <p className="text-2xl font-bold">
                        {studentProgress?.overall_stats?.completed_quizzes || 0}
                      </p>
                    </div>
                  </div>
                </CardContent>
              </Card>
              <Card>
                <CardContent className="p-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-purple-100 flex items-center justify-center">
                      <Trophy className="w-5 h-5 text-purple-600" />
                    </div>
                    <div>
                      <p className="text-sm text-muted-foreground">Average Score</p>
                      <p className="text-2xl font-bold">
                        {Math.round(studentProgress?.overall_stats?.average_score || 0)}%
                      </p>
                    </div>
                  </div>
                </CardContent>
              </Card>
              <Card>
                <CardContent className="p-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-orange-100 flex items-center justify-center">
                      <Star className="w-5 h-5 text-orange-600" />
                    </div>
                    <div>
                      <p className="text-sm text-muted-foreground">Best Score</p>
                      <p className="text-2xl font-bold">
                        {Math.round(studentProgress?.overall_stats?.best_score || 0)}%
                      </p>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </div>

            <Tabs defaultValue="sections" className="space-y-6">
              <TabsList className="grid w-full grid-cols-4">
                <TabsTrigger value="sections">By Subject</TabsTrigger>
                <TabsTrigger value="available">Available</TabsTrigger>
                <TabsTrigger value="completed">Completed</TabsTrigger>
                <TabsTrigger value="analytics">Analytics</TabsTrigger>
              </TabsList>

              <TabsContent value="sections" className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {studentProgress?.subject_progress?.map((subject) => (
                    <Card
                      key={subject.id}
                      className="overflow-hidden hover:shadow-lg transition-shadow cursor-pointer group"
                    >
                      <div className={`h-2 bg-gradient-to-r ${subject.color}`} />
                      <CardHeader className="pb-3">
                        <div className="flex items-start justify-between">
                          <div className="flex items-center gap-3">
                            <div className="text-3xl">{subject.icon}</div>
                            <div>
                              <CardTitle className="group-hover:text-primary transition-colors">
                                {subject.name}
                              </CardTitle>
                              <CardDescription className="mt-1">
                                {subject.completed} of {subject.total_quizzes} completed
                              </CardDescription>
                            </div>
                          </div>
                          <Badge variant="secondary">
                            {Math.round(subject.average_score)}% avg
                          </Badge>
                        </div>
                      </CardHeader>
                      <CardContent className="space-y-4">
                        {/* Progress */}
                        <div className="space-y-2">
                          <div className="flex justify-between text-sm">
                            <span>Progress</span>
                            <span className="font-medium">
                              {subject.completed}/{subject.total_quizzes} completed
                            </span>
                          </div>
                          <div className="w-full bg-gray-200 rounded-full h-2">
                            <div
                              className={`bg-gradient-to-r ${subject.color} h-2 rounded-full transition-all`}
                              style={{ width: `${subject.total_quizzes > 0 ? (subject.completed / subject.total_quizzes) * 100 : 0}%` }}
                            />
                          </div>
                        </div>

                        {/* Stats */}
                        <div className="grid grid-cols-2 gap-4 text-sm">
                          <div>
                            <p className="text-muted-foreground">Total Quizzes</p>
                            <p className="font-medium">{subject.total_quizzes}</p>
                          </div>
                          <div>
                            <p className="text-muted-foreground">Best Score</p>
                            <p className={`font-medium ${getScoreColor(subject.best_score)}`}>
                              {Math.round(subject.best_score)}%
                            </p>
                          </div>
                        </div>

                        <Button className="w-full group-hover:bg-primary/90 transition-colors">
                          <Target className="w-4 h-4 mr-2" />
                          View {subject.name} Quizzes
                        </Button>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              </TabsContent>

              <TabsContent value="available" className="space-y-6">
                <div className="space-y-4">
                  <h3 className="text-xl font-semibold mb-4">📋 Available Quizzes</h3>
                  {quizzes.map((quiz) => (
                    <Card key={quiz.id} className="hover:shadow-lg transition-shadow">
                      <CardContent className="p-6">
                        <div className="flex items-start gap-4">
                          <div className="text-3xl">{quiz.subject_icon}</div>
                          <div className="flex-1">
                            <div className="flex items-start justify-between mb-2">
                              <div>
                                <h4 className="font-semibold text-lg">{quiz.title}</h4>
                                <p className="text-sm text-muted-foreground">{quiz.subject_name}</p>
                              </div>
                              <div className="flex items-center gap-2">
                                <Badge
                                  variant="outline"
                                  className={getDifficultyColor(quiz.difficulty)}
                                >
                                  {quiz.difficulty}
                                </Badge>
                              </div>
                            </div>
                            <div className="grid grid-cols-2 md:grid-cols-3 gap-4 text-sm mb-4">
                              <div className="flex items-center gap-2">
                                <Clock className="w-4 h-4 text-muted-foreground" />
                                <span>{quiz.duration_minutes} minutes</span>
                              </div>
                              <div className="flex items-center gap-2">
                                <FileText className="w-4 h-4 text-muted-foreground" />
                                <span>{quiz.total_questions} questions</span>
                              </div>
                              <div className="flex items-center gap-2">
                                <Target className="w-4 h-4 text-muted-foreground" />
                                <span>{quiz.difficulty}</span>
                              </div>
                            </div>
                            <Button
                              className="w-full md:w-auto"
                              onClick={() => handleQuizStart(quiz)}
                            >
                              <Play className="w-4 h-4 mr-2" />
                              Start Quiz
                            </Button>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                  {quizzes.length === 0 && (
                    <div className="text-center py-8">
                      <FileText className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                      <p className="text-muted-foreground">No quizzes available at the moment.</p>
                    </div>
                  )}
                </div>
              </TabsContent>


              <TabsContent value="completed" className="space-y-6">
                <div className="space-y-4">
                  <h3 className="text-xl font-semibold mb-4">✅ Completed Quizzes</h3>
                  {studentProgress?.recent_attempts?.map((attempt) => (
                    <Card key={attempt.id} className="hover:shadow-lg transition-shadow">
                      <CardContent className="p-6">
                        <div className="flex items-start gap-4">
                          <div className="text-3xl">{attempt.subject_icon}</div>
                          <div className="flex-1">
                            <div className="flex items-start justify-between mb-2">
                              <div>
                                <h4 className="font-semibold text-lg">{attempt.title}</h4>
                                <p className="text-sm text-muted-foreground">{attempt.subject_name}</p>
                              </div>
                              <div className="text-right">
                                <div className={`text-2xl font-bold ${getScoreColor(attempt.score)}`}>
                                  {Math.round(attempt.score)}%
                                </div>
                                <p className="text-sm text-muted-foreground">
                                  {attempt.correct_answers}/{attempt.total_questions} correct
                                </p>
                              </div>
                            </div>
                            <div className="grid grid-cols-2 md:grid-cols-3 gap-4 text-sm mb-4">
                              <div>
                                <p className="text-muted-foreground">Completed</p>
                                <p className="font-medium">
                                  {new Date(attempt.completed_at).toLocaleDateString()}
                                </p>
                              </div>
                              <div>
                                <p className="text-muted-foreground">Time Spent</p>
                                <p className="font-medium">{attempt.time_spent_minutes} minutes</p>
                              </div>
                              <div>
                                <p className="text-muted-foreground">Difficulty</p>
                                <Badge
                                  variant="outline"
                                  className={getDifficultyColor(attempt.difficulty)}
                                >
                                  {attempt.difficulty}
                                </Badge>
                              </div>
                            </div>
                            <div className="flex gap-2">
                              <Button variant="outline" size="sm">
                                View Results
                              </Button>
                              <Button variant="outline" size="sm">
                                Retake Quiz
                              </Button>
                            </div>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                  {(!studentProgress?.recent_attempts || studentProgress.recent_attempts.length === 0) && (
                    <div className="text-center py-8">
                      <CheckCircle2 className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
                      <p className="text-muted-foreground">No completed quizzes yet. Start taking quizzes to see your progress!</p>
                    </div>
                  )}
                </div>
              </TabsContent>

              <TabsContent value="analytics" className="space-y-6">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <Card>
                    <CardHeader>
                      <CardTitle>Performance by Subject</CardTitle>
                      <CardDescription>Your average scores across subjects</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-4">
                      {studentProgress?.subject_progress?.map((subject) => (
                        <div key={subject.id} className="space-y-2">
                          <div className="flex justify-between items-center text-sm">
                            <span className="flex items-center gap-2">
                              <span>{subject.icon}</span>
                              {subject.name}
                            </span>
                            <span className={`font-medium ${getScoreColor(subject.average_score)}`}>
                              {Math.round(subject.average_score)}%
                            </span>
                          </div>
                          <div className="w-full bg-gray-200 rounded-full h-2">
                            <div
                              className={`bg-gradient-to-r ${subject.color} h-2 rounded-full`}
                              style={{ width: `${Math.round(subject.average_score)}%` }}
                            />
                          </div>
                        </div>
                      ))}
                      {(!studentProgress?.subject_progress || studentProgress.subject_progress.length === 0) && (
                        <div className="text-center py-4">
                          <p className="text-muted-foreground text-sm">No data available yet. Take some quizzes to see your performance!</p>
                        </div>
                      )}
                    </CardContent>
                  </Card>

                  <Card>
                    <CardHeader>
                      <CardTitle>Recent Activity</CardTitle>
                      <CardDescription>Your quiz activity over time</CardDescription>
                    </CardHeader>
                    <CardContent>
                      <div className="space-y-4">
                        <div className="flex items-center gap-4 p-3 border rounded-lg">
                          <div className="w-10 h-10 rounded-full bg-green-100 flex items-center justify-center">
                            <CheckCircle2 className="w-5 h-5 text-green-600" />
                          </div>
                          <div className="flex-1">
                            <p className="font-medium">Excellent performance!</p>
                            <p className="text-sm text-muted-foreground">
                              You scored 92% on Cell Biology Quiz
                            </p>
                          </div>
                        </div>
                        <div className="flex items-center gap-4 p-3 border rounded-lg">
                          <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center">
                            <Trophy className="w-5 h-5 text-blue-600" />
                          </div>
                          <div className="flex-1">
                            <p className="font-medium">Quiz streak!</p>
                            <p className="text-sm text-muted-foreground">
                              You've completed 5 quizzes this week
                            </p>
                          </div>
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                </div>
              </TabsContent>
            </Tabs>
          </div>
        </div>
      </SidebarInset>
    </SidebarProvider>
  );
};

export default Quizzes;